def minimax_score(tree, is_maximizing=True):
    def minimax(node, maximizing):
        if not isinstance(node, list):
            return float(node), []

        best_value = None
        best_path = []
        best_idx = 0

        for i, child in enumerate(node):
            value, path = minimax(child, not maximizing)

            if best_value is None or (maximizing and value > best_value) or (not maximizing and value < best_value):
                best_value = value
                best_path = path
                best_idx = i

        return best_value, [best_idx] + best_path

    value, path = minimax(tree, is_maximizing)
    return round(value, 4), path
